import React, { useState, useEffect } from 'react';
import '../css/CocktailMenu.css';

const signatureCocktails = [
    {
        id: 's1',
        name: 'Citrus Mirage',
        ingredients: ['Gin Tanqueray Sevilla', 'Liquore al Mandarino', 'Aperol', 'Succo di Limone'],
        image: '/foto/CITRUS_MIRAGE.png',
        color: '#FF8C00',
    },
    {
        id: 's2',
        name: 'Wild Ruby',
        ingredients: ['Sciroppo Frutti Rossi', 'Succo Maracuja', 'Succo Lampone', 'Succo Ananas', 'Succo Melograno'],
        image: '../foto/WILD_RUBY.png',
        color: '#C41E3A',
    },
    {
        id: 's3',
        name: 'Mango Royal',
        ingredients: ['Vodka Premium', 'Sciroppo al Mango', 'Succo Lime', 'Succo Ananas'],
        image: null,
        color: '#FFB347',
    },
    {
        id: 's4',
        name: 'Midnight Whisper',
        ingredients: ['Whisky', 'Liquore al Caffè', 'Sciroppo alla Cannella', 'Sciroppo Pop Corn'],
        image: '/foto/MIDNIGHT_WHISPER.png',
        color: '#4A2C2A',
    },
    {
        id: 's5',
        name: 'Poire Dorée',
        ingredients: ['François Peyrott', 'Bitter Orange', 'Frangelico', 'Top di Soda'],
        image: '/foto/POIRE_DORÉE.png',
        color: '#D4A017',
    },
    {
        id: 's6',
        name: 'Cinnamon Sunset',
        ingredients: ['Gin Tanqueray', 'Aperol', 'Cannella', "Succo d'Arancia", 'Succo Limone'],
        image: '/foto/CINNAMON_SUNSET.png',
        color: '#E25822',
    },
];

const classicCocktails = [
    { id: 'c1', name: 'Alexander', ingredients: ['Cognac', 'Crema di Cacao', 'Panna', 'Noce Moscata'], image: '/foto/ALEXANDER.png', color: '#8B4513' },
    { id: 'c2', name: 'Americano', ingredients: ['Bitter Campari', 'Vermouth Rosso', 'Soda'], image: '/foto/AMERICANO.png', color: '#DC143C' },
    { id: 'c3', name: 'American Beauty', ingredients: ['Brandy', 'Vermouth Dry', 'Crème de Menthe', 'Porto Rosso', "Succo d'Arancia"], image: '/foto/AMERICAN_BEAUTY.png', color: '#C71585' },
    { id: 'c4', name: 'B52', ingredients: ['Kahlúa', 'Baileys', 'Grand Marnier'], image: '/foto/B52.png', color: '#8B6914' },
    { id: 'c5', name: 'Bellini', ingredients: ['Rum', 'Lime', 'Cocco', 'Menta'], image: '/foto/BELLINI.png', color: '#FFDAB9' },
    { id: 'c6', name: 'Black Russian', ingredients: ['Vodka', 'Liquore al Caffè'], image: '/foto/BLACK_RUSSIAN.png', color: '#2C2C2C' },
    { id: 'c7', name: 'Bloody Mary', ingredients: ['Vodka', 'Succo di Pomodoro', 'Limone', 'Tabasco', 'Salsa Worcestershire', 'Sale', 'Pepe'], image: null, color: '#B22222' },
    { id: 'c8', name: 'Bonaparte', ingredients: ['Cranberry', 'Prosecco', 'Gocce di Limone'], image: null, color: '#FFD700' },
    { id: 'c9', name: 'Caipirinha', ingredients: ['Cachaça', 'Zucchero di Canna', 'Lime'], image: '/foto/CAIPIRINHA.png', color: '#32CD32' },
    { id: 'c10', name: 'Capiroska', ingredients: ['Vodka', 'Lime', 'Zucchero di Canna'], image: '/foto/CAIPIROSKA.png', color: '#9ACD32' },
    { id: 'c11', name: 'Cosmopolitan', ingredients: ['Vodka Limone', 'Cointreau', 'Succo Lime', 'Succo Cranberry'], image: '/foto/COSMOPOLITAN.png', color: '#FF69B4' },
    { id: 'c12', name: 'Cuba Libre', ingredients: ['Rum Bianco', 'Coca Cola'], image: '/foto/CUBA_LIBRE.png', color: '#8B0000' },
    { id: 'c13', name: 'Daiquiri', ingredients: ['Rum Bianco', 'Succo Lime', 'Sciroppo di Zucchero'], image: '/foto/DAIQUIRI.png', color: '#E0FFFF' },
    { id: 'c14', name: 'Cocktail Martini', ingredients: ['Gin', 'Dry Vermouth'], image: '/foto/COCKTAIL_MARTINI.png', color: '#C0C0C0' },
    { id: 'c15', name: 'Garibaldi', ingredients: ['Bitter Campari', "Succo d'Arancia"], image: null, color: '#FF4500' },
    { id: 'c16', name: 'Godfather', ingredients: ['Scotch Whiskey', 'Amaretto'], image: '/foto/GOD_FATHER.png', color: '#DAA520' },
    { id: 'c17', name: 'Godmother', ingredients: ['Vodka Liscia', 'Amaretto'], image: '/foto/GOD_MOTHER.png', color: '#DEB887' },
    { id: 'c18', name: 'Gin Fizz', ingredients: ['Gin', 'Succo di Limone', 'Sciroppo di Zucchero', 'Soda'], image: '/foto/GIN_FIZZ.png', color: '#87CEEB' },
    { id: 'c19', name: 'Irish Coffee', ingredients: ['Irish Whisky', 'Caffè', 'Zucchero di Canna', 'Panna Fresca'], image: null, color: '#6F4E37' },
    { id: 'c20', name: 'Jack & Coca', ingredients: ['Jack Daniels', 'Coca Cola'], image: '/foto/JACK_&_COLA.png', color: '#3B2F2F' },
    { id: 'c21', name: 'Jäger Mojito', ingredients: ['Jägermeister', 'Zucchero di Canna', 'Lime', 'Arancia', 'Menta', 'Ginger Ale'], image: '/foto/JEGER_MOJITO.png', color: '#2E8B57' },
    { id: 'c22', name: 'Japanese Ice Tea', ingredients: ['Vodka', 'Gin', 'Rum Bianco', 'Midori', 'Sweet & Sour', 'Lemonsoda'], image: '/foto/JAPANESE_ICE_TEA.png', color: '#66CDAA' },
    { id: 'c23', name: 'June Bug', ingredients: ['Midori', 'Malibu', 'Liquore Banana', 'Sweet & Sour', "Succo d'Ananas"], image: '/foto/JUNE_BUG.png', color: '#ADFF2F' },
    { id: 'c24', name: 'Long Beach Ice Tea', ingredients: ['Vodka', 'Gin', 'Rum Bianco', 'Triple Sec', 'Sweet & Sour', 'Succo Cranberry'], image: null, color: '#DB7093' },
    { id: 'c25', name: 'Long Island Ice Tea', ingredients: ['Vodka', 'Gin', 'Rum Bianco', 'Triple Sec', 'Sweet & Sour', 'Coca Cola'], image: null, color: '#D2691E' },
    { id: 'c26', name: 'Pornostar Martini', ingredients: ['Vodka alla Vaniglia', 'Passion Fruit Purée', 'Liquore al Frutto della Passione', 'Succo di Limone', 'Sciroppo alla Vaniglia'], image: '/foto/PORNOSTAR_MARTINI.png', color: '#FFD700' },
    { id: 'c27', name: 'Margarita', ingredients: ['Tequila', 'Cointreau', 'Succo Lime'], image: null, color: '#7FFF00' },
    { id: 'c28', name: 'Mai Tai', ingredients: ['Rum Bianco', 'Rum Scuro', 'Orange Curaçao', 'Lime', 'Sciroppo Orzata', 'Granatina'], image: null, color: '#FF6347' },
    { id: 'c29', name: 'Manhattan', ingredients: ['Canadian Whisky', 'Vermouth Rosso', 'Angostura'], image: null, color: '#800020' },
    { id: 'c30', name: 'Miami Ice Tea', ingredients: ['Vodka', 'Gin', 'Rum Bianco', 'Triple Sec', 'Blu Curaçao', 'Sweet & Sour', 'Coca Cola'], image: null, color: '#00CED1' },
    { id: 'c31', name: 'Mimosa', ingredients: ['Prosecco', "Succo d'Arancia"], image: null, color: '#FFA500' },
    { id: 'c32', name: 'Mojito', ingredients: ['Rum Bianco', 'Zucchero di Canna', 'Lime', 'Menta', 'Soda'], image: null, color: '#00FA9A' },
    { id: 'c33', name: 'Moscow Mule', ingredients: ['Vodka', 'Ginger Beer', 'Succo Lime'], image: null, color: '#B87333' },
    { id: 'c34', name: 'Negroni', ingredients: ['Gin', 'Vermouth Rosso', 'Bitter Campari'], image: null, color: '#CC5500' },
    { id: 'c35', name: 'Negroni Sbagliato', ingredients: ['Bitter Campari', 'Vermouth Rosso', 'Prosecco'], image: null, color: '#E34234' },
    { id: 'c36', name: 'Old Fashioned', ingredients: ['Bourbon Whisky', 'Zucchero', 'Angostura', 'Acqua'], image: null, color: '#CC7722' },
    { id: 'c37', name: 'Piña Colada', ingredients: ['Rum Bianco', 'Latte di Cocco', 'Ananas'], image: null, color: '#FFFACD' },
    { id: 'c38', name: 'Rossini', ingredients: ['Prosecco', 'Purea di Fragola'], image: null, color: '#FF2052' },
    { id: 'c39', name: 'Sex on the Beach', ingredients: ['Vodka', 'Peach Tree', "Succo d'Arancia", 'Cranberry'], image: null, color: '#FF7F50' },
    { id: 'c40', name: 'Tintoretto', ingredients: ['Prosecco', 'Sciroppo di Melograno'], image: null, color: '#E30B5C' },
];

/* ── Componente placeholder per cocktail senza foto ── */
function CocktailPlaceholder({ name, color }) {
    return (
        <div className="cocktail-placeholder" style={{ '--accent-color': color }}>
            <div className="placeholder-icon">🍸</div>
            <span className="placeholder-text">{name}</span>
        </div>
    );
}

/* ── MODAL ── */
function Modal({ cocktail, onClose }) {
    const [imgLoaded, setImgLoaded] = useState(false);
    const [imgError, setImgError] = useState(false);

    useEffect(() => {
        const handleKey = (e) => { if (e.key === 'Escape') onClose(); };
        document.body.style.overflow = 'hidden';
        window.addEventListener('keydown', handleKey);
        return () => {
            document.body.style.overflow = '';
            window.removeEventListener('keydown', handleKey);
        };
    }, [onClose]);

    const hasImage = cocktail.image && !imgError;

    return (
        <div className="modal-overlay" onClick={onClose}>
            <div
                className="modal-content"
                style={{ '--accent-color': cocktail.color }}
                onClick={(e) => e.stopPropagation()}
            >
                <button className="modal-close" onClick={onClose}>✕</button>

                <div className="modal-image-wrapper">
                    <div className="modal-image-glow" />
                    {hasImage ? (
                        <>
                            {!imgLoaded && <div className="image-placeholder modal-placeholder" />}
                            <img
                                src={cocktail.image}
                                alt={cocktail.name}
                                className={`modal-image ${imgLoaded ? 'loaded' : ''}`}
                                onLoad={() => setImgLoaded(true)}
                                onError={() => setImgError(true)}
                            />
                        </>
                    ) : (
                        <CocktailPlaceholder name={cocktail.name} color={cocktail.color} />
                    )}
                </div>

                <h2 className="modal-name">{cocktail.name}</h2>
                <div className="modal-divider" />
                <h3 className="modal-ingredients-title">Ingredienti</h3>
                <ul className="modal-ingredients-list">
                    {cocktail.ingredients.map((ing, i) => (
                        <li key={i} className="modal-ingredient" style={{ animationDelay: `${i * 0.07}s` }}>
                            <span className="ingredient-dot" />
                            {ing}
                        </li>
                    ))}
                </ul>
            </div>
        </div>
    );
}

/* ── CARD ── */
function CocktailCard({ cocktail, onClick }) {
    const [imgLoaded, setImgLoaded] = useState(false);
    const [imgError, setImgError] = useState(false);

    const hasImage = cocktail.image && !imgError;

    return (
        <div
            className="cocktail-card"
            style={{ '--accent-color': cocktail.color }}
            onClick={onClick}
        >
            <div className="card-glow" />
            <div className="card-content">
                <div className="card-image-wrapper">
                    {hasImage ? (
                        <>
                            {!imgLoaded && <div className="image-placeholder" />}
                            <img
                                src={cocktail.image}
                                alt={cocktail.name}
                                className={`card-image ${imgLoaded ? 'loaded' : ''}`}
                                onLoad={() => setImgLoaded(true)}
                                onError={() => setImgError(true)}
                            />
                        </>
                    ) : (
                        <CocktailPlaceholder name={cocktail.name} color={cocktail.color} />
                    )}
                    <div className="card-image-overlay" />
                </div>
                <div className="card-info">
                    <h2 className="cocktail-name">{cocktail.name}</h2>
                    <span className="card-tap-hint">Tocca per i dettagli</span>
                </div>
            </div>
        </div>
    );
}

/* ── MENU PRINCIPALE ── */
export default function CocktailMenu() {
    const [category, setCategory] = useState(null);
    const [selectedCocktail, setSelectedCocktail] = useState(null);

    const currentList = category === 'signature' ? signatureCocktails : classicCocktails;

    if (!category) {
        return (
            <div className="menu-wrapper">
                <div className="menu-bg" />
                <header className="menu-header">
                    <p className="menu-subtitle">✦ Benvenuti ✦</p>
                    <h1 className="menu-title">Gran Caffè Margherita</h1>
                    <div className="header-line" />
                    <p className="menu-choose">Scegli la tua esperienza</p>
                </header>

                <div className="category-selection">
                    <button className="category-btn signature-btn" onClick={() => setCategory('signature')}>
                        <div className="cat-img-wrapper">
                            <img src="/foto/CITRUS_MIRAGE.png" alt="Signature" className="cat-img" />
                            <div className="cat-img-overlay" />
                        </div>
                        <div className="cat-text">
                            <span className="cat-label">Signature Cocktails</span>
                            <span className="cat-desc">Le nostre creazioni esclusive</span>
                        </div>
                    </button>

                    <button className="category-btn classic-btn" onClick={() => setCategory('classic')}>
                        <div className="cat-img-wrapper">
                            <img src="/foto/AMERICANO.png" alt="Classici" className="cat-img" />
                            <div className="cat-img-overlay" />
                        </div>
                        <div className="cat-text">
                            <span className="cat-label">Cocktail Classici</span>
                            <span className="cat-desc">I grandi classici intramontabili</span>
                        </div>
                    </button>
                </div>

                <footer className="menu-footer">
                    <p>Si prega di bere responsabilmente · Drink Responsibly</p>
                </footer>
            </div>
        );
    }

    return (
        <div className="menu-wrapper">
            <div className="menu-bg" />
            <header className="menu-header">
                <p className="menu-subtitle">
                    {category === 'signature' ? '✦ Signature Cocktails ✦' : '✦ Cocktail Classici ✦'}
                </p>
                <h1 className="menu-title">Gran Caffè Margherita</h1>
                <div className="header-line" />
                <button className="back-btn" onClick={() => setCategory(null)}>← Torna al Menù</button>
            </header>

            <div className="cocktail-grid">
                {currentList.map((cocktail) => (
                    <CocktailCard
                        key={cocktail.id}
                        cocktail={cocktail}
                        onClick={() => setSelectedCocktail(cocktail)}
                    />
                ))}
            </div>

            {selectedCocktail && (
                <Modal cocktail={selectedCocktail} onClose={() => setSelectedCocktail(null)} />
            )}

            <footer className="menu-footer">
                <p>Si prega di bere responsabilmente · Drink Responsibly</p>
            </footer>
        </div>
    );
}
